sql:
SELECT DISTINCT r.region_name, r.city, r.state, r.zip_code
FROM regions r
JOIN user_interactions ui ON r.region_id = ui.region_id;

external_knowledge:
- "Active users" refers to users who are currently present in the users table; 
- "Recent interactions" are those that occurred within the last five years from the current date; 
- "Preferred user price ranges," "minimum bedrooms and bathrooms," and "square footage preferences" indicate the ranges or minimums that users have specified for their ideal properties in each region.

sql:
SELECT COUNT(interaction_id) AS total_interactions
FROM user_interactions
WHERE user_id = 1 AND region_id = 2;

WITH Alice_Searches AS (
    SELECT ui.region_id, up.num_bedrooms
    FROM user_interactions ui
    JOIN user_preferences up ON ui.user_id = up.user_id
    WHERE ui.user_id = (
        SELECT user_id FROM users WHERE user_name = 'Alice Johnson'
    ) AND ui.interaction_type = 'search'
)
SELECT AVG(num_bedrooms) AS avg_bedrooms
FROM Alice_Searches;
